{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a geometric packing optimization problem. To solve it, we need to handle spatial partitioning, area constraints, and point containment. I will delegate the core geometric logic and the optimization strategy to specialized helpers.",
  "helpers": [
    {
      "label": "spatial_partitioning_expert",
      "instructions": "Develop a spatial partitioning algorithm (such as a Quadtree or a k-d tree) that can manage a 10000x10000 grid. The algorithm must support inserting rectangles and checking for overlaps with existing rectangles while maintaining efficient lookup for point containment."
    },
    {
      "label": "area_optimization_expert",
      "instructions": "Given a target point (x, y) and a target area A, derive a mathematical method to generate an axis-aligned rectangle that contains (x, y) and has area approximately A. The method should prioritize shapes that are not too thin to maximize the probability of successful packing in a crowded field."
    },
    {
      "label": "greedy_packing_scheduler",
      "instructions": "Design a scheduling heuristic to order the advertisers. The heuristic should consider the target area and the density of points in specific regions. Propose a strategy (e.g., largest area first, or most constrained point first) to minimize the total wasted space and maximize the number of successful placements."
    }
  ],
  "synthesis_brief": "Combine the spatial partitioning structure with the area generation logic. Use the greedy scheduler to process advertisers one by one, attempting to place the generated rectangle into the spatial structure. If a collision occurs, implement a fallback mechanism to shrink the rectangle or shift it slightly while maintaining point containment, then aggregate the final score based on the area deviation and successful placements."
}

